          existing = customers.find(c => normalizePhone(c.phone) === phone);
      }

      const now = Date.now();
      if (existing) {
          // IMPORTANT: If customer address is verified/pinned, DO NOT overwrite it with order address
          const newAddress = existing.isAddressVerified ? existing.address : (order.address || existing.address);

          const updated: Customer = {
              ...existing,
              address: newAddress,
              phone: order.customerPhone || existing.phone,
              lastOrderDate: now,
              totalOrders: (existing.totalOrders || 0) + 1,
              updatedAt: now
          };
          await storageService.upsertCustomer(updated);
      } else if (order.customerName) {
          const newCust: Customer = {
              id: order.customerId || uuidv4(),
