    })}</div>{order.notes && (<div className="flex items-start gap-1.5 mt-1.5 ml-1"><i className="fas fa-sticky-note text-yellow-500 text-[10px] mt-0.5"></i><p className="text-[10px] text-yellow-700 italic line-clamp-2 leading-tight">{order.notes}</p></div>)}</div><div className="px-3 py-2 mt-auto border-t border-gray-50"><div className="flex justify-between items-end"><span className="text-[10px] font-bold text-gray-400 uppercase mb-1">Tổng thu:</span><div className="text-right"><div className="font-black text-gray-900 text-lg leading-none">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}<span className="text-xs text-gray-400 font-normal ml-0.5">đ</span></div>{!isCompleted && (<div className="flex justify-end mt-1"><PaymentBadge /></div>)}</div></div></div><div className="p-3 pt-0"><div className="grid grid-cols-[1fr_1fr_1fr_2fr] gap-2 mb-2"><button onClick={handleMessengerClick} className="flex items-center justify-center py-2 rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 transition-colors" title="Nhắn tin"><i className="fas fa-comment-dots"></i></button><button onClick={(e) => { e.stopPropagation(); handlePrint(); }} className="flex items-center justify-center py-2 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors" title="In phiếu"><i className="fas fa-print"></i></button><button onClick={(e) => { e.stopPropagation(); requestQR(e); }} className="flex items-center justify-center py-2 rounded-lg bg-gray-100 text-gray-600 hover:bg-blue-50 hover:text-blue-600 transition-colors" title="Mã QR"><i className="fas fa-qrcode"></i></button><button onClick={nextStatus} className={`flex items-center justify-center gap-2 py-2 rounded-lg font-bold text-xs text-white shadow-sm transition-all active:scale-95 ${order.status === OrderStatus.DELIVERED ? 'bg-green-500 hover:bg-green-600' : 'bg-gray-800 hover:bg-gray-900'}`}>{order.status === OrderStatus.DELIVERED ? (<>Hoàn tất <i className="fas fa-check"></i></>) : (<>Tiếp theo <i className="fas fa-arrow-right"></i></>)}</button></div><div className="flex justify-between items-center text-[10px] text-gray-400 pt-1 border-t border-gray-50"><div className="font-mono">{order.batchId || 'NO-BATCH'}</div><div className="flex gap-3">{order.status !== OrderStatus.DELIVERED && onSplitBatch && (<button onClick={(e) => { e.stopPropagation(); onSplitBatch(order); }} className="hover:text-orange-500 font-bold transition-colors" title="Chuyển sang lô sau">Hoãn</button>)}{onMoveBatch && (<button onClick={(e) => { e.stopPropagation(); onMoveBatch(order); }} className="hover:text-indigo-500 font-bold transition-colors" title="Chuyển lô">Chuyển</button>)}</div></div></div>{showCompactPaymentChoice && (<div className="fixed inset-0 z-[99999] bg-gray-900/50 backdrop-blur-sm flex items-center justify-center p-4" onClick={(e) => { e.stopPropagation(); setShowCompactPaymentChoice(false); }}><div className="bg-white w-full max-w-xs rounded-xl shadow-2xl p-4" onClick={e => e.stopPropagation()}><h3 className="text-center font-bold text-gray-800 mb-3 text-sm uppercase">Hoàn tất đơn hàng</h3><div className="grid grid-cols-2 gap-3"><button onClick={(e) => { e.stopPropagation(); handleFinishOrder(PaymentMethod.CASH); }} className="p-3 bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 rounded-lg text-center"><span className="block text-xl">💵</span><span className="text-xs font-bold text-emerald-700">TIỀN MẶT</span></button><button onClick={(e) => { e.stopPropagation(); handleFinishOrder(PaymentMethod.TRANSFER); }} className="p-3 bg-blue-50 hover:bg-blue-100 border border-blue-200 rounded-lg text-center"><span className="block text-xl">💳</span><span className="text-xs font-bold text-blue-700">CHUYỂN KHOẢN</span></button></div></div></div>)}</div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Product, Order, PriceTier } from '../types';
import { storageService, generateProductSku, normalizeString } from '../services/storageService';
import ConfirmModal from './ConfirmModal';
import { formatDistanceToNow } from 'date-fns';
import { vi } from 'date-fns/locale';

// --- PRODUCT DETAIL MODAL (VIEW HISTORY) ---
interface ProductDetailModalProps {
    isOpen: boolean;
    onClose: () => void;
    product: Product;
    onImport: () => void;
    onAdjust: () => void;
    onDelete?: () => void;
}

export const ProductDetailModal: React.FC<ProductDetailModalProps> = ({ isOpen, onClose, product, onImport, onAdjust, onDelete }) => {
    const [history, setHistory] = useState<{order: Order, quantity: number}[]>([]);

    useEffect(() => {
        if(isOpen && product) {
            setHistory(storageService.getProductOrderHistory(product.id));
        }
    }, [isOpen, product]);

    const batchExportHistory = useMemo(() => {
        const groups = new Map<string, { batchId: string, quantity: number, date: number, orderCount: number }>();
        history.forEach(item => {
            const batchId = item.order.batchId || 'Chưa phân lô';
            if (!groups.has(batchId)) { groups.set(batchId, { batchId, quantity: 0, date: item.order.createdAt, orderCount: 0 }); }
            const group = groups.get(batchId)!;
            group.quantity += Number(item.quantity) || 0;
            group.orderCount += 1;
            group.date = Math.max(group.date, item.order.createdAt);
        });
        return Array.from(groups.values()).sort((a, b) => b.date - a.date);
    }, [history]);

    const importHistory = useMemo(() => {
        const records = product.importHistory || [];
        return [...records].sort((a, b) => b.date - a.date);
    }, [product]);

    if (!isOpen) return null;

    const totalSold = batchExportHistory.reduce((sum, b) => sum + b.quantity, 0);
    const currentStock = product.stockQuantity || 0;
    const historyImportTotal = importHistory.reduce((sum, r) => sum + r.quantity, 0);
    const hasHistory = historyImportTotal > 0;
    const calculatedTotalImported = hasHistory ? historyImportTotal : (product.totalImported || (currentStock + totalSold));
    const isLow = currentStock < 5;

    return (
        <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-5 border-b border-gray-100 flex justify-between items-start bg-gray-50">
                    <div>
                        <div className="flex items-center gap-2">
                            <h3 className="font-black text-xl text-gray-800 uppercase tracking-tighter">{product.name}</h3>
                            <button onClick={onAdjust} className="w-6 h-6 rounded-full bg-white border-2 border-gray-800 text-gray-800 hover:bg-gray-100 flex items-center justify-center transition-all shadow-sm" title="Sửa thông tin"><i className="fas fa-pen text-[10px]"></i></button>
                        </div>
                        <div className="text-[10px] text-gray-400 font-black mt-1 uppercase tracking-widest">Mã hàng: {product.id}</div>
                    </div>
                    <button onClick={onClose} className="w-8 h-8 rounded-full bg-white text-gray-400 hover:text-gray-600 flex items-center justify-center"><i className="fas fa-times"></i></button>
                </div>

                <div className="flex-grow overflow-y-auto p-6 space-y-6">
                    <div className="bg-white rounded-2xl border-2 border-gray-800 shadow-sm p-4 relative overflow-hidden">
                        <div className="flex justify-between items-end mb-2">
                            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tồn kho hiện tại</span>
                            <div className="text-right">
                                <span className={`text-4xl font-black tracking-tighter ${isLow ? 'text-red-600' : 'text-gray-800'}`}>{currentStock}</span>
                                <span className="text-xs text-gray-400 font-bold uppercase ml-1">/ {calculatedTotalImported}</span>
                            </div>
                        </div>
                        <div className="w-full bg-gray-100 rounded-full h-3 mb-4 overflow-hidden border border-gray-200">
                            <div className={`h-full rounded-full transition-all duration-500 ${isLow ? 'bg-red-500' : 'bg-green-500'}`} style={{ width: `${calculatedTotalImported > 0 ? Math.min(100, (currentStock / calculatedTotalImported) * 100) : 0}%` }}></div>
                        </div>
                        <button onClick={onImport} className="w-full py-3 bg-black text-white rounded-xl font-bold uppercase text-xs shadow-lg hover:bg-gray-800 transition-all flex items-center justify-center gap-2">
                            <i className="fas fa-plus-circle"></i> Nhập thêm hàng
                        </button>
                    </div>

                    <div>
                        <h4 className="text-xs font-black text-gray-800 uppercase mb-3 flex items-center gap-2"><i className="fas fa-history text-blue-500"></i> Lịch sử bán hàng</h4>
                        <div className="space-y-2">
                            {batchExportHistory.length === 0 ? <div className="text-center text-xs text-gray-400 py-4 italic">Chưa có dữ liệu bán hàng</div> : 
                            batchExportHistory.map((batch, idx) => (
                                <div key={idx} className="flex justify-between items-center p-3 bg-gray-50 rounded-xl border border-gray-100">
                                    <div>
                                        <div className="font-bold text-gray-800 text-xs uppercase">{batch.batchId}</div>
                                        <div className="text-[10px] text-gray-400 font-medium">{formatDistanceToNow(batch.date, { addSuffix: true, locale: vi })}</div>
                                    </div>
                                    <div className="text-right">
                                        <span className="block font-black text-gray-800 text-sm">-{batch.quantity}</span>
                                        <span className="text-[9px] text-gray-500">{batch.orderCount} đơn</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- PRODUCT EDIT MODAL (NEW DESIGN) ---
interface ProductEditModalProps {
    isOpen: boolean;
    onClose: () => void;
    product: Product | null;
    onSave: (product: Product, isImport: boolean, qty: number) => Promise<void>;
    initialMode?: 'IMPORT' | 'SET';
    allProducts?: Product[];
    onSwitchToProduct?: (p: Product) => void;
}

export const ProductEditModal: React.FC<ProductEditModalProps> = ({ 
    isOpen, onClose, product, onSave, initialMode = 'SET', allProducts, onSwitchToProduct 
}) => {
    const [activeTab, setActiveTab] = useState<'IMPORT' | 'INFO'>('INFO');

    // Form States
    const [name, setName] = useState('');
    const [price, setPrice] = useState<number>(0);
    const [importPrice, setImportPrice] = useState<number>(0);
    const [stock, setStock] = useState<number>(0);
    const [priceTiers, setPriceTiers] = useState<PriceTier[]>([]);

    // Import Tab specific state
    const [importQty, setImportQty] = useState<number>(0);
    const [importNote, setImportNote] = useState('');

    useEffect(() => {
        if (isOpen) {
            if (product) {
                setName(product.name);
                setPrice(product.defaultPrice);
                setImportPrice(product.importPrice || 0);
                setStock(product.stockQuantity || 0);
                setPriceTiers(product.priceTiers || []);
                setImportQty(0);
                setImportNote('');
                setActiveTab(initialMode === 'IMPORT' ? 'IMPORT' : 'INFO');
            } else {
                // New Product
                setName('');
                setPrice(0);
                setImportPrice(0);
                setStock(0);
                setPriceTiers([]);
                setActiveTab('INFO');
            }
        }
    }, [isOpen, product, initialMode]);

    const handleSave = async () => {
        if (!name.trim()) { toast.error("Tên sản phẩm không được trống"); return; }

        // Check duplicates if creating new
        if (!product && allProducts) {
            const sku = generateProductSku(name);
            const exists = allProducts.find(p => p.id === sku);
            if (exists) {
                if (onSwitchToProduct) {
                    toast("Sản phẩm đã tồn tại, chuyển sang chế độ sửa.");
                    onSwitchToProduct(exists);
                    return;
                } else {
                    toast.error("Sản phẩm này đã tồn tại!");
                    return;
                }
            }
        }

        const baseProduct: Product = product || {
            id: generateProductSku(name),
            name,
            defaultPrice: price,
            stockQuantity: 0,
            totalImported: 0
        };

        if (activeTab === 'IMPORT') {
            // Import Mode
            if (importQty <= 0) { toast.error("Số lượng nhập phải > 0"); return; }
            await onSave({
                ...baseProduct,
                importPrice: importPrice // Update latest import price
            }, true, importQty);
        } else {
            // Info Mode (Update / Set Stock)
            await onSave({
                ...baseProduct,
                name,
                defaultPrice: price,
                importPrice,
                stockQuantity: stock, // Overwrite stock
                priceTiers
            }, false, 0);
        }
    };

    const addTier = () => setPriceTiers([...priceTiers, { minQty: 2, price: price }]);
    const removeTier = (idx: number) => setPriceTiers(priceTiers.filter((_, i) => i !== idx));
    const updateTier = (idx: number, field: keyof PriceTier, val: number) => {
        const newTiers = [...priceTiers];
        newTiers[idx] = { ...newTiers[idx], [field]: val };
        setPriceTiers(newTiers);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[110] bg-gray-900/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
            <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>

                {/* Custom Tab Switcher */}
                <div className="p-2 bg-gray-100 m-4 rounded-xl flex gap-1 border border-gray-200">
                    {product && (
                        <button 
                            onClick={() => setActiveTab('IMPORT')}
                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'IMPORT' ? 'bg-white text-green-700 shadow-sm' : 'text-gray-400 hover:bg-gray-200'}`}
                        >
                            <i className="fas fa-arrow-down"></i> Nhập Kho
                        </button>
                    )}
                    <button 
                        onClick={() => setActiveTab('INFO')}
                        className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'INFO' ? 'bg-white text-indigo-700 shadow-sm' : 'text-gray-400 hover:bg-gray-200'}`}
                    >
                        <i className="fas fa-cog"></i> {product ? 'Thông tin & Giá' : 'Tạo sản phẩm mới'}
                    </button>
                </div>

                {/* Content Area */}
                <div className="flex-grow overflow-y-auto px-6 pb-6 pt-0 no-scrollbar">

                    {/* --- IMPORT TAB --- */}
                    {activeTab === 'IMPORT' && product && (
                        <div className="space-y-6 animate-slide-up">
                            <div className="text-center">
                                <h3 className="text-lg font-black text-gray-800 uppercase">{product.name}</h3>
                                <p className="text-xs text-gray-500 font-bold">Tồn hiện tại: {product.stockQuantity}</p>
                            </div>

                            <div className="bg-green-50 rounded-2xl p-6 border-2 border-green-100 flex flex-col items-center">
                                <label className="text-[10px] font-black text-green-600 uppercase tracking-widest mb-2">Số lượng nhập thêm</label>
                                <div className="flex items-center gap-4">
                                    <button onClick={() => setImportQty(Math.max(0, importQty - 1))} className="w-10 h-10 bg-white rounded-full text-green-600 shadow-sm hover:bg-green-100 font-bold text-xl">-</button>
                                    <input 
                                        type="number" 
                                        value={importQty || ''} 
                                        onChange={e => setImportQty(Number(e.target.value))}
                                        className="w-32 text-center bg-transparent text-5xl font-black text-green-700 outline-none placeholder-green-200/50"
                                        placeholder="0"
