          let updated = false;
          const newItems = o.items.map(item => {
              if (item.productId) {
                  const p = products.find(prod => prod.id === item.productId);
                  if (p) {
                      // RE-CALCULATE PRICE based on tiers/quantity
                      const { price: newCorrectPrice } = calculateProductPrice(p, item.quantity);

                      if (item.name !== p.name || item.price !== newCorrectPrice || item.importPrice !== p.importPrice) {
                          updated = true;
                          return {
                              ...item,
                              name: p.name,
                              price: newCorrectPrice, // Use calculated price
                              importPrice: p.importPrice
                          };
                      }
                  }
              }
              return item;
          });

          if (updated) {
              const newTotal = newItems.reduce((s, it) => s + (it.price * it.quantity), 0);
              ordersToUpdate.push({ ...o, items: newItems, totalPrice: newTotal, updatedAt: Date.now() });
          }
      });

      if (ordersToUpdate.length > 0) {
          await storageService.saveOrdersList(ordersToUpdate);
      }
      return ordersToUpdate.length;
  },

