import jsPDF from 'jspdf';
import { Order, OrderStatus, PaymentMethod } from '../types';
import { normalizeString } from './storageService';

export const pdfService = {
    generateCompactList: async (orders: Order[], batchName: string, onProgress?: (progress: number) => void) => {
        const doc = new jsPDF();
        const pageWidth = doc.internal.pageSize.getWidth();
        const margin = 10;
        let y = 20;

        // Use standard font. Note: Standard PDF fonts do not support Vietnamese characters well.
        // Ideally, a custom font (ttf base64) should be added. 
        // Here we normalize strings to remove accents for compatibility if custom font isn't loaded globally.
        // Assuming normalizeString removes accents.

        doc.setFontSize(14);
        doc.text(`DANH SACH DON HANG: ${normalizeString(batchName)}`, margin, y);
        y += 10;
        doc.setFontSize(10);

        const total = orders.length;
        for (let i = 0; i < total; i++) {
            const o = orders[i];

            // Price Text Logic
            let priceText = new Intl.NumberFormat('vi-VN').format(o.totalPrice);
            if (o.paymentMethod === PaymentMethod.PAID) {
                priceText += " (DA TT)";
            } else if (o.paymentMethod === PaymentMethod.TRANSFER) {
                if (o.paymentVerified) {
                    priceText += " (CK ROI)";
                } else {
                    priceText += " (CK)";
                }
            } else if (o.paymentMethod === PaymentMethod.CASH) {
                if (o.status === OrderStatus.DELIVERED || o.status === OrderStatus.CANCELLED) {
                    priceText += " (TM)"; 
                }
            }

            // Normalize text to ensure it renders on standard fonts
            const name = normalizeString(o.customerName);
            const address = normalizeString(o.address);
            const items = normalizeString(o.items.map(it => `${it.name}(x${it.quantity})`).join(', '));
            const note = o.notes ? `Note: ${normalizeString(o.notes)}` : '';

            // Layout
            // 1. Name & Price
            const line1 = `${i + 1}. [${o.id}] ${name} - ${priceText}`;
            // 2. Address
            const line2 = `   DC: ${address}`;
            // 3. Items
            const line3 = `   Hang: ${items} ${note}`;

            if (y > 270) {
                doc.addPage();
                y = 20;
            }

            doc.setFont("helvetica", "bold");
            doc.text(line1, margin, y);
            y += 5;

            doc.setFont("helvetica", "normal");
            doc.text(line2, margin, y);
            y += 5;

            doc.text(line3, margin, y);
            y += 8;

            if (onProgress) {
                onProgress(Math.round(((i + 1) / total) * 100));
                // Yield to main thread
                await new Promise(r => setTimeout(r, 0));
            }
        }
        doc.save(`List-${normalizeString(batchName)}.pdf`);
    },

    generateInvoiceBatch: async (orders: Order[], batchName: string, onProgress?: (progress: number) => void) => {
        const doc = new jsPDF();
        const total = orders.length;

        for (let i = 0; i < total; i++) {
            if (i > 0) doc.addPage();
            const o = orders[i];

            doc.setFontSize(18);
            doc.text("PHIEU GIAO HANG", 105, 20, { align: "center" });

            doc.setFontSize(12);
            doc.text(`Ma don: #${o.id}`, 20, 40);
            doc.text(`Khach hang: ${normalizeString(o.customerName)}`, 20, 50);
            doc.text(`SDT: ${o.customerPhone}`, 20, 60);

            const addrLines = doc.splitTextToSize(`Dia chi: ${normalizeString(o.address)}`, 170);
            doc.text(addrLines, 20, 70);

            let y = 70 + (addrLines.length * 5) + 10;

            doc.text("Chi tiet:", 20, y);
            y += 10;

            o.items.forEach(item => {
                doc.text(`- ${normalizeString(item.name)} (x${item.quantity}): ${new Intl.NumberFormat('vi-VN').format(item.price * item.quantity)}`, 25, y);
                y += 7;
            });

            y += 10;
            doc.setFont("helvetica", "bold");
            doc.text(`TONG CONG: ${new Intl.NumberFormat('vi-VN').format(o.totalPrice)}`, 20, y);

            if (o.notes) {
                y += 10;
                doc.setFont("helvetica", "italic");
                doc.text(`Ghi chu: ${normalizeString(o.notes)}`, 20, y);
            }
            doc.setFont("helvetica", "normal");

            if (onProgress) {
                onProgress(Math.round(((i + 1) / total) * 100));
                await new Promise(r => setTimeout(r, 0));
            }
        }

        doc.save(`Invoices-${normalizeString(batchName)}.pdf`);
    },

    generateUserGuidePDF: async () => {
        const doc = new jsPDF();
        doc.setFontSize(18);
        doc.text("HUONG DAN SU DUNG ECOGO", 105, 20, { align: "center" });

        doc.setFontSize(12);
        let y = 40;

