// Helper function to remove accents for standard PDF fonts
const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D");
};

