import { GoogleGenAI, Type } from "@google/genai";
import { Product, Order, SmartParseResult, RawPDFImportData, Customer } from '../types';
import toast from 'react-hot-toast';

export type PostStyle = 'DEFAULT' | 'FOMO' | 'STORY' | 'MINIMAL' | 'FUNNY';

// Helper để làm sạch JSON (loại bỏ markdown block nếu có)
const cleanJson = (text: string): string => {
    if (!text) return "{}";
    let clean = text.trim();
    clean = clean.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');
    return clean;
};

// Cấu trúc khởi tạo chuẩn: Luôn lấy từ process.env.API_KEY
// Lưu ý: API_KEY này được Vite inject vào khi build dựa trên file .env hoặc biến môi trường hệ thống
const getAIInstance = () => {
    const key = process.env.API_KEY;
    if (!key || key === "undefined" || key.trim() === "") {
        throw new Error("MISSING_API_KEY");
    }
    return new GoogleGenAI({ apiKey: key });
};

export const generateSocialPost = async (products: Product[], location: string, time: string, style: PostStyle = 'DEFAULT'): Promise<string> => {
    try {
        const ai = getAIInstance();
        const productList = products.map(p => {
            let info = `- ${p.name}: ${new Intl.NumberFormat('vi-VN').format(p.defaultPrice)} VND`;
            if (p.priceTiers && p.priceTiers.length > 0) {
                const tiers = p.priceTiers
                    .sort((a,b) => a.minQty - b.minQty)
                    .map(t => `(>=${t.minQty} món: ${new Intl.NumberFormat('vi-VN').format(t.price)})`)
                    .join(', ');
                info += ` [GIÁ SỈ: ${tiers}]`;
            }
            return info;
        }).join('\n');

        let styleInstruction = "";
        switch (style) {
            case 'FOMO': styleInstruction = "Phong cách: GẤP GÁP, KHAN HIẾM. Dùng từ ngữ mạnh."; break;
            case 'STORY': styleInstruction = "Phong cách: KỂ CHUYỆN, TÂM TÌNH ấm áp."; break;
            case 'FUNNY': styleInstruction = "Phong cách: HÀI HƯỚC, BẮT TREND vui nhộn."; break;
            case 'MINIMAL': styleInstruction = "Phong cách: TỐI GIẢN, chỉ menu và giá."; break;
            default: styleInstruction = "Phong cách: THÂN THIỆN, NHIỆT TÌNH."; break;
        }

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Bạn là trợ lý viết bài bán hàng. ${styleInstruction}\nDanh sách: ${productList}\nGiao tại: ${location} lúc ${time}\nYêu cầu: Cấu trúc rõ ràng, icon sinh động, làm nổi bật giá sỉ nếu có.`,
            config: { temperature: 0.8 }
        });

        return response.text || "Không thể tạo bài đăng.";
    } catch (e: any) {
        if (e.message === "MISSING_API_KEY") {
            toast.error("Chưa cấu hình API Key trong file .env!");
            return "⚠️ Lỗi: Thiếu API Key.";
        }
        toast.error("Lỗi kết nối AI: " + e.message);
        return "⚠️ Lỗi AI.";
    }
};

