export const verifyAddress = async (address: string): Promise<{ address: string }> => {
    try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Chuẩn hóa địa chỉ: "${address}". Trả về JSON { "address": "..." }`,
